    @Environment(\.accessibilityReduceMotion) private var reduceMotion

    private let barCount = 4
    private let barWidth: CGFloat = 3

    var body: some View {
        HStack(spacing: 2) {
            ForEach(0..<barCount, id: \.self) { i in
