// MARK: - From Submissions/clipcheck/DietaryProfile.swift

//  DietaryProfile.swift
//  ClipCheck

import Foundation

// MARK: - Allergen

enum Allergen: String, CaseIterable, Identifiable {
    case peanuts, treeNuts, dairy, gluten, shellfish, eggs, fish, soy

    var id: String { rawValue }

    var label: String {
        switch self {
        case .peanuts: return "Peanuts"
        case .treeNuts: return "Tree Nuts"
        case .dairy: return "Dairy"
        case .gluten: return "Gluten"
        case .shellfish: return "Shellfish"
        case .eggs: return "Eggs"
        case .fish: return "Fish"
        case .soy: return "Soy"
        }
    }

    var emoji: String {
        switch self {
        case .peanuts: return "🥜"
        case .treeNuts: return "🌰"
        case .dairy: return "🥛"
        case .gluten: return "🌾"
        case .shellfish: return "🦐"
        case .eggs: return "🥚"
        case .fish: return "🐟"
        case .soy: return "🫘"
        }
    }

    /// Parse from URL param value (e.g. "peanuts" or "tree-nuts")
    init?(urlValue: String) {
        let normalized = urlValue.lowercased().replacingOccurrences(of: "-", with: "")
            .replacingOccurrences(of: "_", with: "")
        switch normalized {
        case "peanuts", "peanut": self = .peanuts
        case "treenuts", "treenut": self = .treeNuts
        case "dairy", "milk", "lactose": self = .dairy
        case "gluten", "wheat": self = .gluten
        case "shellfish", "shrimp", "crab": self = .shellfish
        case "eggs", "egg": self = .eggs
        case "fish": self = .fish
        case "soy", "soya": self = .soy
        default: return nil
        }
    }
}

// MARK: - Dietary Preference

enum DietaryPreference: String, CaseIterable, Identifiable {
    case vegetarian, vegan, halal, kosher

    var id: String { rawValue }

    var label: String {
        switch self {
        case .vegetarian: return "Vegetarian"
        case .vegan: return "Vegan"
        case .halal: return "Halal"
        case .kosher: return "Kosher"
        }
    }

    var emoji: String {
        switch self {
        case .vegetarian: return "🌱"
        case .vegan: return "🌿"
        case .halal: return "☪️"
        case .kosher: return "✡️"
        }
    }

    init?(urlValue: String) {
        let normalized = urlValue.lowercased()
        switch normalized {
        case "vegetarian", "veg": self = .vegetarian
        case "vegan": self = .vegan
        case "halal": self = .halal
        case "kosher": self = .kosher
        default: return nil
        }
    }
}

// MARK: - Dietary Profile

struct DietaryProfile {
    var allergens: Set<Allergen> = []
    var preferences: Set<DietaryPreference> = []

    var isEmpty: Bool { allergens.isEmpty && preferences.isEmpty }

    /// Human-readable summary, e.g. "Dairy-free, Gluten-free, Halal"
    var summary: String {
        var parts: [String] = []
        for a in Allergen.allCases where allergens.contains(a) {
            parts.append("\(a.label)-free")
        }
        for p in DietaryPreference.allCases where preferences.contains(p) {
            parts.append(p.label)
        }
        return parts.isEmpty ? "No restrictions" : parts.joined(separator: ", ")
    }

    /// Prompt fragment for Gemini
    var promptFragment: String {
        guard !isEmpty else { return "" }
        var parts: [String] = []
        if !allergens.isEmpty {
            parts.append("Allergies: \(allergens.map(\.label).joined(separator: ", "))")
        }
        if !preferences.isEmpty {
            parts.append("Diet: \(preferences.map(\.label).joined(separator: ", "))")
        }
        return parts.joined(separator: ". ") + "."
    }

    /// Parse from URL query params: ?allergens=peanuts,dairy&diet=halal
    static func fromQuery(_ params: [String: String]) -> DietaryProfile? {
        var profile = DietaryProfile()
        if let allergenStr = params["allergens"] {
            for raw in allergenStr.split(separator: ",") {
                if let a = Allergen(urlValue: String(raw)) {
                    profile.allergens.insert(a)
                }
            }
        }
        if let dietStr = params["diet"] {
            for raw in dietStr.split(separator: ",") {
                if let p = DietaryPreference(urlValue: String(raw)) {
                    profile.preferences.insert(p)
                }
            }
        }
        return profile.isEmpty ? nil : profile
    }
}

// MARK: - From Submissions/clipcheck/ElevenLabsService.swift

//  ElevenLabsService.swift
//  ClipCheck

import AVFoundation
import Foundation

@Observable
final class ElevenLabsService: NSObject, AVAudioPlayerDelegate, AVSpeechSynthesizerDelegate {
    enum PlaybackState { case idle, loading, playing }
    private(set) var state: PlaybackState = .idle

    private var player: AVAudioPlayer?
    private var synthesizer: AVSpeechSynthesizer?

    func speak(_ text: String) {
        if state == .playing { stop(); return }
        guard state == .idle else { return }
        state = .loading

        let key = Secrets.elevenLabsAPIKey
        guard !key.isEmpty, key != "YOUR_ELEVENLABS_API_KEY_HERE" else {
            speakOnDevice(text)
            return
        }

        Task {
            do {
                let url = URL(string: "https://api.elevenlabs.io/v1/text-to-speech/21m00Tcm4TlvDq8ikWAM")!
                var req = URLRequest(url: url)
                req.httpMethod = "POST"
                req.setValue(key, forHTTPHeaderField: "xi-api-key")
                req.setValue("application/json", forHTTPHeaderField: "Content-Type")
                req.timeoutInterval = 15
                req.httpBody = try JSONSerialization.data(withJSONObject: [
                    "text": text,
                    "model_id": "eleven_multilingual_v2"
                ])

                let (data, resp) = try await URLSession.shared.data(for: req)
                let code = (resp as? HTTPURLResponse)?.statusCode ?? 0

                guard (200...299).contains(code), data.count > 100 else {
                    print("[TTS] ElevenLabs HTTP \(code), falling back to on-device")
                    await MainActor.run { self.speakOnDevice(text) }
                    return
                }

                await MainActor.run { self.playData(data) }
            } catch {
                print("[TTS] ElevenLabs error: \(error), falling back to on-device")
                await MainActor.run { self.speakOnDevice(text) }
            }
        }
    }

    func stop() {
        player?.stop(); player = nil
        synthesizer?.stopSpeaking(at: .immediate); synthesizer = nil
        state = .idle
    }

    // MARK: - ElevenLabs playback

    private func playData(_ data: Data) {
        do {
            try AVAudioSession.sharedInstance().setCategory(.playback, mode: .spokenAudio)
            try AVAudioSession.sharedInstance().setActive(true)
            let p = try AVAudioPlayer(data: data)
            p.delegate = self
            p.play()
            player = p
            state = .playing
        } catch {
            print("[TTS] Playback error: \(error)")
            state = .idle
        }
    }

    nonisolated func audioPlayerDidFinishPlaying(_ player: AVAudioPlayer, successfully flag: Bool) {
        DispatchQueue.main.async { [weak self] in
            self?.player = nil
            self?.state = .idle
        }
    }

    // MARK: - On-device fallback

    private func speakOnDevice(_ text: String) {
        let synth = AVSpeechSynthesizer()
        synth.delegate = self
        synthesizer = synth
        let utt = AVSpeechUtterance(string: text)
        utt.voice = AVSpeechSynthesisVoice(language: "en-US")
        utt.rate = AVSpeechUtteranceDefaultSpeechRate * 0.92
        utt.pitchMultiplier = 1.05
        do {
            try AVAudioSession.sharedInstance().setCategory(.playback, mode: .spokenAudio)
            try AVAudioSession.sharedInstance().setActive(true)
        } catch {}
        synth.speak(utt)
        state = .playing
    }

    nonisolated func speechSynthesizer(_ synthesizer: AVSpeechSynthesizer, didFinish utterance: AVSpeechUtterance) {
        DispatchQueue.main.async { [weak self] in
            self?.synthesizer = nil
            self?.state = .idle
        }
    }
}

// MARK: - From Submissions/clipcheck/GeminiService.swift

//  GeminiService.swift
//  ClipCheck — Restaurant Safety Score via App Clip

import Foundation

@Observable
final class GeminiService {
    private(set) var result: AdvisorResult?
    private(set) var isLoading = false
    private(set) var error: String?

    private static var apiKey: String { Secrets.geminiAPIKey }
    private static let endpoint = "https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent"

    struct AdvisorResult {
        let summary: String
        let concerns: String
        let recommendations: String
        let riskLevel: String
        let weatherTip: String
        let timeTip: String
        let allergenWarning: String
        let rawResponse: String
    }

    func analyze(_ restaurant: RestaurantData, dietary: DietaryProfile = DietaryProfile(), personalization: PersonalizationContext? = nil) {
        guard !isLoading else { return }
        isLoading = true
        error = nil
        result = nil

        let ctx = personalization ?? PersonalizationContext(dietary: dietary)

        Task {
            do {
                let advisor = try await fetchAdvisorResult(for: restaurant, context: ctx)
                await MainActor.run {
                    self.result = advisor
                    self.isLoading = false
                }
            } catch {
                print("[GeminiService] ERROR: \(error)")
                print("[GeminiService] Localized: \(error.localizedDescription)")
                await MainActor.run {
                    self.error = error.localizedDescription
                    self.result = Self.fallback(for: restaurant, context: ctx)
                    self.isLoading = false
                }
            }
        }
    }

    // MARK: - Network

    private func fetchAdvisorResult(for restaurant: RestaurantData, context: PersonalizationContext) async throws -> AdvisorResult {
        let prompt = Self.buildPrompt(for: restaurant, context: context)

        var urlComponents = URLComponents(string: Self.endpoint)!
        urlComponents.queryItems = [URLQueryItem(name: "key", value: Self.apiKey)]

        var request = URLRequest(url: urlComponents.url!)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.timeoutInterval = 15

        let body: [String: Any] = [
            "contents": [
                ["parts": [["text": prompt]]]
            ],
            "generationConfig": [
                "temperature": 0.7,
                "maxOutputTokens": 1200
            ]
        ]
        request.httpBody = try JSONSerialization.data(withJSONObject: body)

        let (data, response) = try await URLSession.shared.data(for: request)

        let statusCode = (response as? HTTPURLResponse)?.statusCode ?? 0
        guard let httpResponse = response as? HTTPURLResponse,
              (200...299).contains(httpResponse.statusCode) else {
            let bodyString = String(data: data, encoding: .utf8) ?? "<non-UTF8 data, \(data.count) bytes>"
            print("[GeminiService] HTTP \(statusCode) — request failed")
            print("[GeminiService] Response body: \(bodyString)")
            throw GeminiError.httpError(statusCode)
        }

        return try Self.parseResponse(data)
    }

    // MARK: - Prompt

    private static func buildPrompt(for restaurant: RestaurantData, context: PersonalizationContext) -> String {
        var lines: [String] = []
        lines.append("You are a food safety advisor helping diners make informed decisions. A customer just scanned a QR code at \(restaurant.name) and wants to know if it's safe to eat here right now.")
        lines.append("")
        lines.append("Here is the official public health inspection data:")
        lines.append("")
        lines.append("Restaurant: \(restaurant.name)")
        lines.append("Address: \(restaurant.address)")
        lines.append("Cuisine: \(restaurant.type)")
        lines.append("Computed Trust Score: \(restaurant.trustScore)/100 (\(restaurant.trustLevel.label))")

        // Personalization context: weather, time, dietary
        lines.append("")
        lines.append(context.promptFragment)

        if !context.dietary.isEmpty {
            lines.append("")
            lines.append("IMPORTANT — Customer dietary profile: \(context.dietary.promptFragment)")
            lines.append("All recommendations MUST account for these restrictions. Flag any menu categories that may conflict with these needs.")
        }

        lines.append("")

        if restaurant.inspections.isEmpty {
            lines.append("No inspection records found.")
        } else {
            for (i, inspection) in restaurant.inspections.prefix(3).enumerated() {
                let recency = i == 0 ? " (most recent)" : ""
                lines.append("--- Inspection \(i + 1)\(recency): \(inspection.date) — \(inspection.status) ---")
                if inspection.infractions.isEmpty {
                    lines.append("  No violations found.")
                } else {
                    lines.append("  \(inspection.infractions.count) violation(s):")
                    for infraction in inspection.infractions {
                        lines.append("  [\(infraction.severity)] \(infraction.detail)")
                        if !infraction.action.isEmpty {
                            lines.append("    Action taken: \(infraction.action)")
                        }
                    }
                }
                lines.append("")
            }
        }

        lines.append("Write a safety briefing for the customer. Be specific — reference actual violations, dates, and patterns from the data above. Do NOT be generic. The customer is standing in the restaurant right now and needs actionable advice.")
        lines.append("Factor in the current weather and time of day when making your recommendations — e.g., cold weather favors hot cooked dishes (safer); late afternoon means food may have been sitting longer.")
        lines.append("")
        lines.append("Use EXACTLY this format with plain text only (no markdown, no asterisks, no bullet points):")
        lines.append("")
        lines.append("SUMMARY: Two to three sentences. Mention the restaurant by name, its most recent inspection result and date, and whether the trend is improving or declining. Be specific about what was found.")
        lines.append("")
        lines.append("CONCERNS: One to two sentences about the most worrying violation patterns. Reference specific violations from the data (e.g., \"cold food stored at unsafe temperatures\" not just \"food safety issues\"). If the record is clean, write \"None — this restaurant has a clean inspection record.\"")
        lines.append("")
        lines.append("RECOMMENDATIONS: Two to three specific, practical tips. Tell the customer exactly what to order or avoid based on the violations found AND the current weather/time context. For example: \"It's cold outside so you'll want hot food anyway — stick to grilled items since refrigeration was cited.\" If the record is clean, explain what makes this a confident choice.")
        lines.append("")
        lines.append("WEATHER_TIP: One sentence about how today's weather affects food safety choices at this specific restaurant. Reference the temperature and conditions.")
        lines.append("")
        lines.append("TIME_TIP: One sentence about how the current time of day affects food freshness at this restaurant.")
        lines.append("")
        lines.append("ALLERGEN_WARNING: If the diner specified allergens or dietary restrictions, give specific advice about cross-contamination risk based on the violations found. If no allergens specified, write \"No specific allergen concerns.\"")
        lines.append("")
        lines.append("RISK: Exactly one word: LOW, MODERATE, or HIGH")

        return lines.joined(separator: "\n")
    }

    // MARK: - Parse

    private static func parseResponse(_ data: Data) throws -> AdvisorResult {
        guard let json = try JSONSerialization.jsonObject(with: data) as? [String: Any],
              let candidates = json["candidates"] as? [[String: Any]],
              let first = candidates.first,
              let content = first["content"] as? [String: Any],
              let parts = content["parts"] as? [[String: Any]] else {
            let rawString = String(data: data, encoding: .utf8) ?? "<non-UTF8 data, \(data.count) bytes>"
            print("[GeminiService] Parse failed. Raw response: \(rawString)")
            throw GeminiError.parseError
        }

        // Gemini 2.5 Flash may return "thought" parts before the actual text.
        // Find the last non-thought text part (the actual response).
        let textParts = parts.filter { ($0["thought"] as? Bool) != true }
        guard let text = textParts.last?["text"] as? String ?? parts.last?["text"] as? String else {
            print("[GeminiService] No text part found in \(parts.count) parts")
            throw GeminiError.parseError
        }

        return parseStructured(text)
    }

    private static func parseStructured(_ text: String) -> AdvisorResult {
        print("[GeminiService] Raw response:\n\(text)")

        // Strip markdown bold/italic markers (**, *, __)
        let cleaned = text
            .replacingOccurrences(of: "**", with: "")
            .replacingOccurrences(of: "__", with: "")

        // Normalize alternate label "TIPS:" to "RECOMMENDATIONS:" so the parser finds it
        let normalized = cleaned.replacingOccurrences(
            of: "TIPS:",
            with: "RECOMMENDATIONS:",
            options: .caseInsensitive
        )

        // Known field labels in order of appearance
        let labels = ["SUMMARY:", "CONCERNS:", "RECOMMENDATIONS:", "WEATHER_TIP:", "TIME_TIP:", "ALLERGEN_WARNING:", "RISK:"]

        /// Extracts the content for a given label by capturing everything from that label
        /// until the next known label (or end of text). Handles multi-line values,
        /// case-insensitive label matching, and markdown-stripped text.
        func extract(_ label: String, from text: String) -> String {
            let upper = text.uppercased()
            let labelUpper = label.uppercased()

            // Find where this label starts (case-insensitive)
            guard let labelRange = upper.range(of: labelUpper) else {
                print("[GeminiService] WARNING: Label '\(label)' not found in response")
                return "N/A"
            }

            // Content starts right after the label
            let contentStart = labelRange.upperBound

            // Find where the next known label begins (the earliest one after our label)
            var contentEnd = text.endIndex
            for other in labels where other.uppercased() != labelUpper {
                if let otherRange = upper.range(of: other.uppercased(), range: contentStart..<text.endIndex) {
                    if otherRange.lowerBound < contentEnd {
                        contentEnd = otherRange.lowerBound
                    }
                }
            }

            let value = String(text[contentStart..<contentEnd])
                .trimmingCharacters(in: .whitespacesAndNewlines)

            return value.isEmpty ? "N/A" : value
        }

        let summary = extract("SUMMARY:", from: normalized)
        let concerns = extract("CONCERNS:", from: normalized)
        let recommendations = extract("RECOMMENDATIONS:", from: normalized)
        let weatherTip = extract("WEATHER_TIP:", from: normalized)
        let timeTip = extract("TIME_TIP:", from: normalized)
        let allergenWarning = extract("ALLERGEN_WARNING:", from: normalized)
        var risk = extract("RISK:", from: normalized).uppercased()

        // Log each parsed field
        print("[GeminiService] Parsed SUMMARY: \"\(summary)\"")
        print("[GeminiService] Parsed CONCERNS: \"\(concerns)\"")
        print("[GeminiService] Parsed RECOMMENDATIONS: \"\(recommendations)\"")
        print("[GeminiService] Parsed WEATHER_TIP: \"\(weatherTip)\"")
        print("[GeminiService] Parsed TIME_TIP: \"\(timeTip)\"")
        print("[GeminiService] Parsed ALLERGEN_WARNING: \"\(allergenWarning)\"")
        print("[GeminiService] Parsed RISK: \"\(risk)\"")

        // Warn about N/A fields
        if summary == "N/A" { print("[GeminiService] WARNING: Field SUMMARY extracted as N/A from response") }
        if concerns == "N/A" { print("[GeminiService] WARNING: Field CONCERNS extracted as N/A from response") }
        if recommendations == "N/A" { print("[GeminiService] WARNING: Field RECOMMENDATIONS extracted as N/A from response") }
        if risk == "N/A" { print("[GeminiService] WARNING: Field RISK extracted as N/A from response") }

        // Normalize risk level
        if !["LOW", "MODERATE", "HIGH"].contains(risk) {
            print("[GeminiService] WARNING: Risk level '\(risk)' not recognized, defaulting to MODERATE")
            risk = "MODERATE"
        }

        return AdvisorResult(
            summary: summary,
            concerns: concerns,
            recommendations: recommendations,
            riskLevel: risk,
            weatherTip: weatherTip,
            timeTip: timeTip,
            allergenWarning: allergenWarning,
            rawResponse: text
        )
    }

    // MARK: - Fallback

    static func fallback(for restaurant: RestaurantData, context: PersonalizationContext) -> AdvisorResult {
        let dietary = context.dietary
        let name = restaurant.name
        let score = restaurant.trustScore
        let inspections = restaurant.inspections
        let latest = inspections.first

        // Count violations across all inspections
        let allInfractions = inspections.flatMap { $0.infractions }
        let crucialCount = allInfractions.filter { $0.parsedSeverity == .crucial }.count
        let significantCount = allInfractions.filter { $0.parsedSeverity == .significant }.count
        let totalViolations = allInfractions.count

        let latestDateStr = latest?.date ?? "unknown date"
        let latestStatus = latest?.parsedStatus.label ?? "unknown"
        let latestViolationCount = latest?.infractions.count ?? 0

        // Gather specific violation details
        let recentCrucial = latest?.infractions.filter { $0.parsedSeverity == .crucial } ?? []
        let recentSignificant = latest?.infractions.filter { $0.parsedSeverity == .significant } ?? []
        let topViolation = (recentCrucial.first ?? recentSignificant.first)?.detail

        // Detect violation categories
        let allDetails = allInfractions.map { $0.detail.lowercased() }
        let hasTemperatureIssues = allDetails.contains { $0.contains("temperature") || $0.contains("cold") || $0.contains("hot holding") || $0.contains("refrigerat") }
        let hasSanitationIssues = allDetails.contains { $0.contains("sanit") || $0.contains("clean") || $0.contains("wash") }
        let hasPestIssues = allDetails.contains { $0.contains("pest") || $0.contains("rodent") || $0.contains("insect") || $0.contains("vermin") }
        let hasCrossContamination = allDetails.contains { $0.contains("cross-contam") || $0.contains("raw") || $0.contains("ready-to-eat") }
        let hasStorageIssues = allDetails.contains { $0.contains("storage") || $0.contains("stored") || $0.contains("labelled") || $0.contains("dated") }

        // Determine trend
        let scores = inspections.prefix(3).map { RestaurantDataStore.computeTrustScore(for:
            RestaurantData(id: restaurant.id, name: restaurant.name, address: restaurant.address, type: restaurant.type, inspections: [$0])
        ) }
        let improving = scores.count >= 2 && scores[0] > scores[1]
        let declining = scores.count >= 2 && scores[0] < scores[1]
        let trendNote = improving ? "The trend is improving." : declining ? "The trend is declining." : ""

        var summary: String
        var concerns: String
        var recommendations: String
        var risk: String

        switch restaurant.trustLevel {
        case .safe:
            summary = "\(name) scored \(score)/100 based on \(inspections.count) inspection(s). The most recent inspection on \(latestDateStr) was a \(latestStatus) with \(latestViolationCount == 0 ? "no violations" : "\(latestViolationCount) minor violation(s)")."
            if totalViolations == 0 {
                concerns = "None — this restaurant has a clean inspection record across all \(inspections.count) visit(s)."
            } else {
                concerns = "Only minor issues noted. No crucial or significant violations on record."
            }
            recommendations = "You can order with confidence here. \(name) has consistently met food safety standards. \(trendNote)"
            risk = "LOW"

        case .caution:
            let topIssue = topViolation.map { " The most notable issue: \($0)." } ?? ""
            summary = "\(name) received a \(latestStatus) on \(latestDateStr) with \(latestViolationCount) violation(s), earning a trust score of \(score)/100.\(topIssue) \(trendNote)"

            var concernParts: [String] = []
            if crucialCount > 0 { concernParts.append("\(crucialCount) crucial") }
            if significantCount > 0 { concernParts.append("\(significantCount) significant") }
            let violationSummary = concernParts.isEmpty ? "" : " (\(concernParts.joined(separator: ", ")))"
            concerns = "Inspectors found \(totalViolations) total violation(s)\(violationSummary) across \(inspections.count) inspection(s)."

            var recs: [String] = []
            if hasTemperatureIssues {
                recs.append("Stick to freshly cooked, served-hot dishes — cold food storage was flagged by inspectors.")
            }
            if hasSanitationIssues {
                recs.append("Skip raw items like salads — sanitation practices were cited.")
            }
            if hasCrossContamination {
                recs.append("Avoid raw or undercooked items — cross-contamination was noted.")
            }
            if hasStorageIssues {
                recs.append("Ask about daily specials rather than pre-made items — food storage was a cited issue.")
            }
            if recs.isEmpty {
                recs.append("Opt for well-cooked dishes. Ask your server if issues from the \(latestDateStr) inspection have been addressed.")
            }
            recommendations = recs.joined(separator: " ")
            risk = "MODERATE"

        case .danger:
            let topIssue = topViolation.map { " Inspectors specifically flagged: \($0)." } ?? ""
            summary = "\(name) scored \(score)/100 with a \(latestStatus) on its most recent inspection (\(latestDateStr)). \(latestViolationCount) violation(s) were found, including \(crucialCount) crucial issue(s).\(topIssue)"

            var concernParts: [String] = []
            for v in (recentCrucial + recentSignificant).prefix(2) {
                concernParts.append(v.detail)
            }
            concerns = concernParts.isEmpty
                ? "Multiple food safety failures documented. \(crucialCount) crucial and \(significantCount) significant violation(s) total."
                : concernParts.joined(separator: ". ") + "."

            var recs: [String] = []
            if hasPestIssues {
                recs.append("Pest activity was documented — strongly consider dining elsewhere.")
            }
            if hasTemperatureIssues {
                recs.append("Do not order cold or raw items — temperature control failures were found.")
            }
            if hasSanitationIssues {
                recs.append("Avoid anything that requires manual handling — sanitation violations are on record.")
            }
            if hasCrossContamination {
                recs.append("Skip raw or undercooked items entirely — cross-contamination was flagged.")
            }
            if recs.isEmpty || !hasPestIssues {
                recs.append("Check the Nearby Safer Options section below for alternatives with better records.")
            }
            recommendations = recs.joined(separator: " ")
            risk = "HIGH"
        }

        if !dietary.isEmpty {
            recommendations += " Note: you indicated \(dietary.summary) — always confirm ingredients with your server."
        }

        // Generate weather/time tips from context
        var weatherTip = "N/A"
        if let w = context.weather {
            if w.temperature < 0 {
                weatherTip = "It's \(Int(w.temperature))°C outside — hot, freshly cooked meals are both the warmest and safest choice."
            } else if w.temperature > 25 {
                weatherTip = "It's \(Int(w.temperature))°C outside — warm weather increases bacterial growth risk in improperly stored cold items."
            } else {
                weatherTip = "Current conditions (\(Int(w.temperature))°C, \(w.condition)) don't add significant food safety risk."
            }
        }

        let timeTip = context.mealPeriod.safetyNote

        var allergenWarning = "No specific allergen concerns."
        if !dietary.allergens.isEmpty {
            let allergenList = dietary.allergens.map(\.label).joined(separator: ", ")
            if hasSanitationIssues || hasCrossContamination {
                allergenWarning = "You flagged \(allergenList) allergies. This restaurant has sanitation/handling violations — extra caution recommended for cross-contamination. Ask staff about preparation procedures."
            } else {
                allergenWarning = "You flagged \(allergenList) allergies. No specific allergen-related violations on record, but always confirm with your server."
            }
        }

        return AdvisorResult(
            summary: summary,
            concerns: concerns,
            recommendations: recommendations,
            riskLevel: risk,
            weatherTip: weatherTip,
            timeTip: timeTip,
            allergenWarning: allergenWarning,
            rawResponse: "[Offline analysis — based on inspection data]"
        )
    }
}

// MARK: - Errors

enum GeminiError: LocalizedError {
    case httpError(Int)
    case parseError

    var errorDescription: String? {
        switch self {
        case .httpError(let code): return "API request failed (HTTP \(code))"
        case .parseError: return "Could not parse API response"
        }
    }
}

// MARK: - From Submissions/clipcheck/MenuAnalysisService.swift

//  MenuAnalysisService.swift
//  ClipCheck

import Foundation

// MARK: - Models

struct MenuRecommendation {
    let dishName: String
    let reason: String
}

struct MenuAvoidance {
    let dishName: String
    let reason: String
}

struct MenuAnalysisResult {
    let recommended: [MenuRecommendation]
    let avoid: [MenuAvoidance]
}

// MARK: - Service

@Observable
final class MenuAnalysisService {
    private(set) var result: MenuAnalysisResult?
    private(set) var isLoading = false
    private(set) var error: String?

    private static var apiKey: String { Secrets.geminiAPIKey }
    private static let endpoint = "https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent"

    func analyze(restaurant: RestaurantData, dietary: DietaryProfile, personalization: PersonalizationContext? = nil) {
        guard !isLoading else { return }
        isLoading = true
        error = nil
        result = nil

        let ctx = personalization ?? PersonalizationContext(dietary: dietary)

        Task {
            do {
                let analysis = try await fetchAnalysis(restaurant: restaurant, context: ctx)
                await MainActor.run {
                    self.result = analysis
                    self.isLoading = false
                }
            } catch {
                print("[MenuAnalysis] ERROR: \(error.localizedDescription)")
                await MainActor.run {
                    self.error = error.localizedDescription
                    self.result = Self.fallback(restaurant: restaurant, dietary: dietary)
                    self.isLoading = false
                }
            }
        }
    }

    // MARK: - Network

    private func fetchAnalysis(restaurant: RestaurantData, context: PersonalizationContext) async throws -> MenuAnalysisResult {
        let prompt = Self.buildPrompt(restaurant: restaurant, context: context)

        var urlComponents = URLComponents(string: Self.endpoint)!
        urlComponents.queryItems = [URLQueryItem(name: "key", value: Self.apiKey)]

        var request = URLRequest(url: urlComponents.url!)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.timeoutInterval = 15

        let body: [String: Any] = [
            "contents": [["parts": [["text": prompt]]]],
            "generationConfig": [
                "temperature": 0.7,
                "maxOutputTokens": 600
            ]
        ]
        request.httpBody = try JSONSerialization.data(withJSONObject: body)

        let (data, response) = try await URLSession.shared.data(for: request)

        guard let http = response as? HTTPURLResponse, (200...299).contains(http.statusCode) else {
            let code = (response as? HTTPURLResponse)?.statusCode ?? 0
            print("[MenuAnalysis] HTTP \(code)")
            throw MenuAnalysisError.httpError(code)
        }

        return try Self.parseResponse(data)
    }

    // MARK: - Prompt

    private static func buildPrompt(restaurant: RestaurantData, context: PersonalizationContext) -> String {
        let mealPeriod = context.mealPeriod

        var lines: [String] = []
        lines.append("You are a menu advisor for a diner at \(restaurant.name), a \(restaurant.type) restaurant. It is \(mealPeriod.label.lowercased()) (\(mealPeriod.safetyNote)).")

        // Weather context
        if let w = context.weather {
            lines.append("Current weather: \(Int(w.temperature))°C, \(w.condition). Factor this into your recommendations — cold weather favors hot dishes, hot weather raises risk for improperly stored cold items.")
        }
        lines.append("")

        // Violations context
        let recentViolations = restaurant.inspections.first?.infractions ?? []
        if recentViolations.isEmpty {
            lines.append("This restaurant has a clean inspection record with no violations.")
        } else {
            lines.append("Recent inspection violations:")
            for v in recentViolations.prefix(5) {
                lines.append("- [\(v.severity)] \(v.detail)")
            }
        }

        // Dietary context
        if !context.dietary.isEmpty {
            lines.append("")
            lines.append("Customer dietary restrictions: \(context.dietary.promptFragment)")
            lines.append("All recommendations MUST be safe for these restrictions. All items to avoid must consider these restrictions.")
        }

        lines.append("")
        lines.append("Based on the restaurant type, likely menu, inspection violations, weather, time of day, and dietary needs, respond in EXACTLY this format. Plain text only, no markdown:")
        lines.append("")
        lines.append("RECOMMEND1: [dish name] | [one sentence reason referencing safety, weather, or dietary fit]")
        lines.append("RECOMMEND2: [dish name] | [one sentence reason]")
        lines.append("RECOMMEND3: [dish name] | [one sentence reason]")
        lines.append("AVOID1: [dish name] | [one sentence reason referencing a specific violation or allergen risk]")
        lines.append("AVOID2: [dish name] | [one sentence reason]")
        lines.append("")
        lines.append("Be specific to this restaurant type. A Chinese restaurant should have Chinese dishes, a pizza place should have pizza items, etc. Reference actual violations when explaining what to avoid.")

        return lines.joined(separator: "\n")
    }

    // MARK: - Parse

    private static func parseResponse(_ data: Data) throws -> MenuAnalysisResult {
        guard let json = try JSONSerialization.jsonObject(with: data) as? [String: Any],
              let candidates = json["candidates"] as? [[String: Any]],
              let first = candidates.first,
              let content = first["content"] as? [String: Any],
              let parts = content["parts"] as? [[String: Any]] else {
            throw MenuAnalysisError.parseError
        }

        // Gemini 2.5 Flash may include "thought" parts — skip them
        let textParts = parts.filter { ($0["thought"] as? Bool) != true }
        guard let text = textParts.last?["text"] as? String ?? parts.last?["text"] as? String else {
            throw MenuAnalysisError.parseError
        }

        let cleaned = text.replacingOccurrences(of: "**", with: "").replacingOccurrences(of: "__", with: "")
        print("[MenuAnalysis] Raw:\n\(cleaned)")

        var recommended: [MenuRecommendation] = []
        var avoid: [MenuAvoidance] = []

        for line in cleaned.components(separatedBy: .newlines) {
            let trimmed = line.trimmingCharacters(in: .whitespaces)
            if trimmed.uppercased().hasPrefix("RECOMMEND") {
                // Strip label like "RECOMMEND1: "
                if let colonIdx = trimmed.firstIndex(of: ":") {
                    let content = String(trimmed[trimmed.index(after: colonIdx)...]).trimmingCharacters(in: .whitespaces)
                    let parts = content.split(separator: "|", maxSplits: 1)
                    if let name = parts.first {
                        let reason = parts.count > 1 ? String(parts[1]).trimmingCharacters(in: .whitespaces) : "Safe choice based on inspection data"
                        recommended.append(MenuRecommendation(dishName: String(name).trimmingCharacters(in: .whitespaces), reason: reason))
                    }
                }
            } else if trimmed.uppercased().hasPrefix("AVOID") {
                if let colonIdx = trimmed.firstIndex(of: ":") {
                    let content = String(trimmed[trimmed.index(after: colonIdx)...]).trimmingCharacters(in: .whitespaces)
                    let parts = content.split(separator: "|", maxSplits: 1)
                    if let name = parts.first {
                        let reason = parts.count > 1 ? String(parts[1]).trimmingCharacters(in: .whitespaces) : "May carry risk based on recent violations"
                        avoid.append(MenuAvoidance(dishName: String(name).trimmingCharacters(in: .whitespaces), reason: reason))
                    }
                }
            }
        }

        // Ensure we have at least something
        if recommended.isEmpty {
            return fallback(text: text)
        }

        return MenuAnalysisResult(recommended: Array(recommended.prefix(3)), avoid: Array(avoid.prefix(2)))
    }

    // MARK: - Fallback

    private static func fallback(text: String = "") -> MenuAnalysisResult {
        MenuAnalysisResult(
            recommended: [
                MenuRecommendation(dishName: "Freshly cooked entrée", reason: "Cooked-to-order items minimize food safety risk"),
                MenuRecommendation(dishName: "Hot soup or broth", reason: "High cooking temperatures ensure safety"),
                MenuRecommendation(dishName: "Grilled or baked dish", reason: "Thorough cooking reduces bacterial risk"),
            ],
            avoid: [
                MenuAvoidance(dishName: "Raw or cold-prepared items", reason: "Higher risk if temperature control was cited"),
                MenuAvoidance(dishName: "Pre-made salads or buffet items", reason: "Longer exposure time increases contamination risk"),
            ]
        )
    }

    static func fallback(restaurant: RestaurantData, dietary: DietaryProfile) -> MenuAnalysisResult {
        let violations = restaurant.inspections.first?.infractions ?? []
        let details = violations.map { $0.detail.lowercased() }
        let hasTemp = details.contains { $0.contains("temperature") || $0.contains("cold") || $0.contains("refrigerat") }
        let hasSanitation = details.contains { $0.contains("sanit") || $0.contains("clean") || $0.contains("wash") }

        var recs: [MenuRecommendation] = []
        var avoids: [MenuAvoidance] = []

        // Recommendations based on restaurant type
        let type = restaurant.type.lowercased()
        if type.contains("chinese") || type.contains("asian") {
            recs.append(MenuRecommendation(dishName: "Stir-fried noodles or rice", reason: "High-heat wok cooking ensures food safety"))
            recs.append(MenuRecommendation(dishName: "Hot & sour soup", reason: "Boiled preparation eliminates bacterial risk"))
            recs.append(MenuRecommendation(dishName: "Steamed dumplings", reason: "Steam cooking is one of the safest preparation methods"))
        } else if type.contains("pizza") || type.contains("italian") {
            recs.append(MenuRecommendation(dishName: "Wood-fired pizza", reason: "Oven temperatures exceed 400°F — very safe"))
            recs.append(MenuRecommendation(dishName: "Baked pasta dish", reason: "Thorough oven baking eliminates pathogens"))
            recs.append(MenuRecommendation(dishName: "Minestrone soup", reason: "Boiled soup is a reliably safe choice"))
        } else if type.contains("indian") || type.contains("curry") {
            recs.append(MenuRecommendation(dishName: "Tandoori chicken", reason: "Tandoor oven reaches extreme temperatures"))
            recs.append(MenuRecommendation(dishName: "Dal or lentil curry", reason: "Slow-cooked legumes are thoroughly heated"))
            recs.append(MenuRecommendation(dishName: "Fresh naan bread", reason: "Baked to order in the tandoor"))
        } else {
            recs.append(MenuRecommendation(dishName: "Grilled entrée", reason: "High-heat grilling ensures thorough cooking"))
            recs.append(MenuRecommendation(dishName: "Hot soup", reason: "Boiled preparation is reliably safe"))
            recs.append(MenuRecommendation(dishName: "Baked or roasted dish", reason: "Oven cooking eliminates bacterial risk"))
        }

        // Avoids based on violations
        if hasTemp {
            avoids.append(MenuAvoidance(dishName: "Cold salads or sushi", reason: "Temperature control violations were cited — cold items carry higher risk"))
        } else {
            avoids.append(MenuAvoidance(dishName: "Raw or undercooked items", reason: "Minimize exposure to uncooked ingredients"))
        }
        if hasSanitation {
            avoids.append(MenuAvoidance(dishName: "Fresh-cut fruit or garnishes", reason: "Sanitation issues were flagged — avoid items requiring manual handling"))
        } else {
            avoids.append(MenuAvoidance(dishName: "Buffet or self-serve items", reason: "Extended exposure time increases contamination risk"))
        }

        // Add dietary note to first recommendation
        if !dietary.isEmpty {
            let note = " Confirm with server that this is \(dietary.summary.lowercased())-compatible."
            recs[0] = MenuRecommendation(dishName: recs[0].dishName, reason: recs[0].reason + note)
        }

        return MenuAnalysisResult(recommended: recs, avoid: avoids)
    }
}

enum MenuAnalysisError: LocalizedError {
    case httpError(Int)
    case parseError

    var errorDescription: String? {
        switch self {
        case .httpError(let code): return "Menu analysis failed (HTTP \(code))"
        case .parseError: return "Could not parse menu analysis"
        }
    }
}

// MARK: - From Submissions/clipcheck/PersonalizationContext.swift

//  PersonalizationContext.swift
//  ClipCheck — Restaurant Safety Score via App Clip

import Foundation

// MARK: - Meal Period

enum MealPeriod: String {
    case breakfast = "breakfast"
    case lunchRush = "lunch_rush"
    case afternoon = "afternoon"
    case dinnerRush = "dinner_rush"
    case lateNight = "late_night"

    var label: String {
        switch self {
        case .breakfast: return "Breakfast"
        case .lunchRush: return "Lunch Rush"
        case .afternoon: return "Afternoon"
        case .dinnerRush: return "Dinner Rush"
        case .lateNight: return "Late Night"
        }
    }

    var safetyNote: String {
        switch self {
        case .breakfast:
            return "Early hours — fresh prep, lower volume, generally safer."
        case .lunchRush:
            return "Peak lunch — high turnover means fresher food, but more kitchen pressure."
        case .afternoon:
            return "Mid-afternoon — lower demand, food may have been sitting longer."
        case .dinnerRush:
            return "Dinner rush — similar to lunch, high turnover but more pressure."
        case .lateNight:
            return "Late night — limited fresh prep, more reheated items."
        }
    }

    var sfSymbol: String {
        switch self {
        case .breakfast: return "sunrise.fill"
        case .lunchRush: return "sun.max.fill"
        case .afternoon: return "sun.haze.fill"
        case .dinnerRush: return "sunset.fill"
        case .lateNight: return "moon.fill"
        }
    }

    static func classify(_ date: Date = Date()) -> MealPeriod {
        let hour = Calendar.current.component(.hour, from: date)
        let minute = Calendar.current.component(.minute, from: date)
        let time = hour * 60 + minute // minutes since midnight

        switch time {
        case 360..<630:   return .breakfast     // 6:00 - 10:29
        case 630..<840:   return .lunchRush     // 10:30 - 13:59
        case 840..<1020:  return .afternoon     // 14:00 - 16:59
        case 1020..<1260: return .dinnerRush    // 17:00 - 20:59
        default:          return .lateNight     // 21:00 - 5:59
        }
    }
}

// MARK: - Personalization Context

struct PersonalizationContext {
    let weather: WeatherService.WeatherData?
    let mealPeriod: MealPeriod
    let currentTime: Date
    let dietary: DietaryProfile

    init(
        weather: WeatherService.WeatherData? = nil,
        dietary: DietaryProfile = DietaryProfile(),
        time: Date = Date()
    ) {
        self.weather = weather
        self.mealPeriod = MealPeriod.classify(time)
        self.currentTime = time
        self.dietary = dietary
    }

    /// Formatted prompt fragment for Gemini
    var promptFragment: String {
        var lines: [String] = []
        lines.append("CURRENT CONTEXT:")

        if let w = weather {
            lines.append("- Weather: \(Int(w.temperature))°C, \(w.condition) in Waterloo")
        }

        let formatter = DateFormatter()
        formatter.dateFormat = "h:mm a"
        lines.append("- Time: \(formatter.string(from: currentTime)) (\(mealPeriod.label))")

        if !dietary.allergens.isEmpty {
            lines.append("- Diner's allergens: \(dietary.allergens.map(\.label).joined(separator: ", "))")
        } else {
            lines.append("- Diner's allergens: none specified")
        }

        if !dietary.preferences.isEmpty {
            lines.append("- Diner's dietary preference: \(dietary.preferences.map(\.label).joined(separator: ", "))")
        } else {
            lines.append("- Diner's dietary preference: none specified")
        }

        return lines.joined(separator: "\n")
    }
}

