// MARK: - From Submissions/clipcheck/RestaurantModels.swift

//  RestaurantModels.swift
//  ClipCheck — Restaurant Safety Score via App Clip

import SwiftUI

// MARK: - Colors

let safeColor = Color(red: 0.133, green: 0.773, blue: 0.369)    // #22C55E
let cautionColor = Color(red: 0.961, green: 0.620, blue: 0.043) // #F59E0B
let dangerColor = Color(red: 0.937, green: 0.267, blue: 0.267)  // #EF4444

// MARK: - Trust Level

enum TrustLevel {
    case safe, caution, danger

    var color: Color {
        switch self {
        case .safe: return safeColor
        case .caution: return cautionColor
        case .danger: return dangerColor
        }
    }

    var label: String {
        switch self {
        case .safe: return "Safe"
        case .caution: return "Caution"
        case .danger: return "High Risk"
        }
    }

    var icon: String {
        switch self {
        case .safe: return "checkmark.shield.fill"
        case .caution: return "exclamationmark.shield.fill"
        case .danger: return "xmark.shield.fill"
        }
    }
}

// MARK: - Inspection Status

enum InspectionStatus: String {
    case pass = "Pass"
    case conditionalPass = "Conditional Pass"
    case closed = "Closed"

    init(from raw: String) {
        switch raw {
        case "Pass": self = .pass
        case "Conditional Pass": self = .conditionalPass
        case "Closed": self = .closed
        default: self = .pass
        }
    }

    var baseScore: Double {
        switch self {
        case .pass: return 100
        case .conditionalPass: return 50
        case .closed: return 0
        }
    }

    var color: Color {
        switch self {
        case .pass: return safeColor
        case .conditionalPass: return cautionColor
        case .closed: return dangerColor
        }
    }

    var icon: String {
        switch self {
        case .pass: return "checkmark.circle.fill"
        case .conditionalPass: return "exclamationmark.circle.fill"
        case .closed: return "xmark.circle.fill"
        }
    }

    var label: String { rawValue }
}

// MARK: - Infraction Severity

enum InfractionSeverity {
    case crucial, significant, minor, notApplicable

    init(from raw: String) {
        if raw.hasPrefix("C") { self = .crucial }
        else if raw.hasPrefix("S") { self = .significant }
        else if raw.hasPrefix("M") { self = .minor }
        else { self = .notApplicable }
    }

    var label: String {
        switch self {
        case .crucial: return "Crucial"
        case .significant: return "Significant"
        case .minor: return "Minor"
        case .notApplicable: return "N/A"
        }
    }

    var color: Color {
        switch self {
        case .crucial: return dangerColor
        case .significant: return cautionColor
        case .minor: return .gray
        case .notApplicable: return .secondary
        }
    }

    var penalty: Double {
        switch self {
        case .crucial: return 15
        case .significant: return 8
        case .minor: return 0
        case .notApplicable: return 0
        }
    }
}

// MARK: - Restaurant Data

struct RestaurantData: Codable, Identifiable {
    let id: String
    let name: String
    let address: String
    let type: String
    let inspections: [Inspection]
}

// MARK: - Inspection

struct Inspection: Codable, Identifiable {
    let id: UUID
    let date: String
    let status: String
    let infractions: [Infraction]

    enum CodingKeys: String, CodingKey {
        case date, status, infractions
    }

    init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        self.id = UUID()
        self.date = try container.decode(String.self, forKey: .date)
        self.status = try container.decode(String.self, forKey: .status)
        self.infractions = try container.decode([Infraction].self, forKey: .infractions)
    }

    func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        try container.encode(date, forKey: .date)
        try container.encode(status, forKey: .status)
        try container.encode(infractions, forKey: .infractions)
    }

    var parsedStatus: InspectionStatus {
        InspectionStatus(from: status)
    }

    var parsedDate: Date {
        Self.dateFormatter.date(from: date) ?? Date()
    }

    private static let dateFormatter: DateFormatter = {
        let f = DateFormatter()
        f.dateFormat = "yyyy-MM-dd"
        f.locale = Locale(identifier: "en_US_POSIX")
        return f
    }()
}

// MARK: - Infraction

struct Infraction: Codable, Identifiable {
    let id: UUID
    let detail: String
    let severity: String
    let action: String

    enum CodingKeys: String, CodingKey {
        case detail, severity, action
    }

    init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        self.id = UUID()
        self.detail = try container.decode(String.self, forKey: .detail)
        self.severity = try container.decode(String.self, forKey: .severity)
        self.action = try container.decode(String.self, forKey: .action)
    }

    func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        try container.encode(detail, forKey: .detail)
        try container.encode(severity, forKey: .severity)
        try container.encode(action, forKey: .action)
    }

    var parsedSeverity: InfractionSeverity {
        InfractionSeverity(from: severity)
    }
}

// MARK: - Computed Properties on RestaurantData

extension RestaurantData {
    var trustScore: Int {
        RestaurantDataStore.computeTrustScore(for: self)
    }

    var trustLevel: TrustLevel {
        switch trustScore {
        case 70...100: return .safe
        case 40..<70: return .caution
        default: return .danger
        }
    }

    var lastInspectedLabel: String {
        guard let latest = inspections.first else { return "Unknown" }
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        return formatter.string(from: latest.parsedDate)
    }
}

// MARK: - From Submissions/clipcheck/Secrets.swift

//  Secrets.swift
//  ClipCheck — Restaurant Safety Score via App Clip
//
//  Loads API keys from Secrets.plist so they are never hardcoded in source.
//  Copy Secrets.example.plist to Secrets.plist and fill in your real keys.

import Foundation

enum Secrets {
    private static let values: [String: String] = {
        let candidates = [
            Bundle.main.url(forResource: "Secrets", withExtension: "plist"),
            Bundle.main.url(forResource: "Secrets", withExtension: "plist", subdirectory: "clipcheck"),
        ]
        for case let url? in candidates {
            if let dict = NSDictionary(contentsOf: url) as? [String: String] {
                print("[Secrets] Loaded from: \(url.lastPathComponent)")
                return dict
            }
        }
        print("[Secrets] WARNING: Secrets.plist not found in bundle. API features will use fallback behavior.")
        return [:]
    }()

    static var geminiAPIKey: String {
        let key = values["GEMINI_API_KEY"] ?? ""
        if key.isEmpty || key == "YOUR_GEMINI_API_KEY_HERE" {
            print("[Secrets] WARNING: GEMINI_API_KEY is missing or placeholder. Gemini features will use fallback behavior.")
        }
        return key
    }

    static var elevenLabsAPIKey: String {
        let key = values["ELEVENLABS_API_KEY"] ?? values["ELEVEN_LABS_API_KEY"] ?? ""
        if key.isEmpty || key == "YOUR_ELEVENLABS_API_KEY_HERE" {
            print("[Secrets] WARNING: ELEVENLABS_API_KEY is missing or placeholder. TTS features will be disabled.")
        }
        return key
    }
}

// MARK: - From Submissions/clipcheck/WeatherService.swift

//  WeatherService.swift
//  ClipCheck — Restaurant Safety Score via App Clip

import Foundation

@Observable
final class WeatherService {
    private(set) var weather: WeatherData?
    private(set) var isLoading = false

    struct WeatherData {
        let temperature: Double
        let condition: String
        let weatherCode: Int

        var sfSymbol: String {
            switch weatherCode {
            case 0: return "sun.max.fill"
            case 1...3: return "cloud.fill"
            case 45, 48: return "cloud.fog.fill"
            case 51...57: return "cloud.drizzle.fill"
            case 61...67: return "cloud.rain.fill"
            case 71...77: return "cloud.snow.fill"
            case 80...82: return "cloud.heavyrain.fill"
            case 95...99: return "cloud.bolt.rain.fill"
            default: return "cloud.fill"
            }
        }

        var temperatureLabel: String {
            "\(Int(temperature))°C"
        }
    }

    func fetch() {
        guard !isLoading, weather == nil else { return }
        isLoading = true

        Task {
            do {
                let data = try await fetchFromAPI()
                await MainActor.run {
                    self.weather = data
                    self.isLoading = false
                }
            } catch {
                print("[WeatherService] Error: \(error), using fallback")
                await MainActor.run {
                    self.weather = Self.fallback
                    self.isLoading = false
                }
            }
        }
    }

    // MARK: - Open-Meteo API (free, no key)

    private func fetchFromAPI() async throws -> WeatherData {
        // Waterloo, ON coordinates
        let url = URL(string: "https://api.open-meteo.com/v1/forecast?latitude=43.4723&longitude=-80.5449&current=temperature_2m,weather_code")!
        var request = URLRequest(url: url)
        request.timeoutInterval = 8

        let (data, response) = try await URLSession.shared.data(for: request)

        guard let http = response as? HTTPURLResponse, (200...299).contains(http.statusCode) else {
            throw WeatherError.httpError
        }

        guard let json = try JSONSerialization.jsonObject(with: data) as? [String: Any],
              let current = json["current"] as? [String: Any],
              let temp = current["temperature_2m"] as? Double,
              let code = current["weather_code"] as? Int else {
            throw WeatherError.parseError
        }

        return WeatherData(
            temperature: temp,
            condition: Self.conditionName(for: code),
            weatherCode: code
        )
    }

    // MARK: - Weather Code Mapping

    private static func conditionName(for code: Int) -> String {
        switch code {
        case 0: return "Clear sky"
        case 1: return "Mainly clear"
        case 2: return "Partly cloudy"
        case 3: return "Overcast"
        case 45, 48: return "Foggy"
        case 51, 53, 55: return "Drizzle"
        case 56, 57: return "Freezing drizzle"
        case 61, 63, 65: return "Rain"
        case 66, 67: return "Freezing rain"
        case 71, 73, 75: return "Snow"
        case 77: return "Snow grains"
        case 80, 81, 82: return "Rain showers"
        case 85, 86: return "Snow showers"
        case 95: return "Thunderstorm"
        case 96, 99: return "Thunderstorm with hail"
        default: return "Cloudy"
        }
    }

    // MARK: - Fallback (Waterloo in March)

    static let fallback = WeatherData(
        temperature: -5.0,
        condition: "Snowy",
        weatherCode: 71
    )
}

enum WeatherError: LocalizedError {
    case httpError
    case parseError

    var errorDescription: String? {
        switch self {
        case .httpError: return "Weather API request failed"
        case .parseError: return "Could not parse weather data"
        }
    }
}

